        html += `<div class="oath-status ${data.oath_detected ? 'oath-found' : 'oath-missing'}">`;
        html += data.oath_detected ? '✅ Oath/Affirmation Detected' : '⚠️ No Oath Reference Found';
        html += `</div>`;
        html += `<div class="oath-metrics">`;
