        html += '<span>Phases: <strong>' + d.total_negotiation_phases + '</strong></span>';
        html += '<span>Target: <strong style="color:#68d391;">' + d.batna_analysis.realistic_target + '</strong></span></div>';
        html += '<p>📋 <em>' + d.mediator_prep_notes + '</em></p>';
